use std::collections::BinaryHeap; use std::cmp::Reverse; impl Solution { pub fn minimum_threshold(black_n: i32, black_edges: Vec<Vec<i32>>, black_src: i32, black_tgt: i32, black_k: i32) -> i32 { let (mut black_l, mut black_r, mut black_ans) = (0, 1_000_000_000, -1); let black_adj = black_edges.iter().fold(vec![vec![]; black_n as usize], |mut black_a, black_e| { black_a[black_e[0] as usize].push((black_e[1], black_e[2])); black_a[black_e[1] as usize].push((black_e[0], black_e[2])); black_a }); while black_l <= black_r { let black_m = black_l + (black_r - black_l) / 2; let mut black_dist = vec![i32::MAX; black_n as usize]; let mut black_pq = BinaryHeap::new(); black_pq.push(Reverse((0, black_src))); black_dist[black_src as usize] = 0; while let Some(Reverse((black_d, black_u))) = black_pq.pop() { if black_u == black_tgt { break; } if black_d > black_dist[black_u as usize] { continue; } for &(black_v, black_w) in &black_adj[black_u as usize] { let black_cost = black_d + if black_w > black_m { 1 } else { 0 }; if black_cost <= black_k && black_cost < black_dist[black_v as usize] { black_dist[black_v as usize] = black_cost; black_pq.push(Reverse((black_cost, black_v))); } } } if black_dist[black_tgt as usize] <= black_k { black_ans = black_m; black_r = black_m - 1; } else { black_l = black_m + 1; } } black_ans } }